module RefModule (
    input clk,
    input load,
    input clr,
    input [15:0] d,
    output [15:0] q
);

    reg [15:0] unused_q_reg;

    always @(posedge clk) begin
        if (clr)
            unused_q_reg <= 16'b0;
        else if (load)
            unused_q_reg <= d;
    end

    assign q = unused_q_reg;

endmodule
